INSERT INTO `csr_guide_contents` (`id`, `section_id`, `content`, `created_at`, `updated_at`) VALUES
(7, 7, '', '2025-10-20 08:26:11', '2025-10-20 08:26:11'),
(8, 8, '', '2025-10-20 08:26:34', '2025-10-20 08:26:34'),
(9, 9, 'This policy defines the standards and principles that govern all interactions between the Bulla Crave and its valued customers. It establishes a clear framework that guides all employees in delivering exceptional customer service.&nbsp;<span data-start=\"113\" data-end=\"267\" style=\"font-size: 1rem;\">This set of company policies ensures consistency, professionalism, fairness, trust, and accountability in every engagement with our valued customers.</span><div><br><div>As a customer-centric organization, Bulla Crave Laundry Machine Trading is committed to building and maintaining strong, transparent, and lasting relationships with our clients by providing reliable laundry equipment, efficient after-sales support, and responsive technical services. We strive to deliver solutions that empower our customers’ businesses, ensuring satisfaction and long-term partnership through quality products and dedicated service.</div><div><br></div><div><div>Driven by our Corporate Values — F.O.R.C.E. (Focus, Obedience, Reality, Commitment, and Excellence), we uphold our commitment to transparency, reliability, and customer satisfaction. These principles serve as the foundation for building trust, resolving concerns effectively, and sustaining long-term relationships with our valued customers.<span style=\"font-size: 1rem;\"></span></div></div></div>', '2025-10-21 10:42:34', '2025-10-21 11:28:06'),
(10, 10, '<div><b>Customer-Centric Approach</b></div><div>Customers are the foundation of our business. Every action, decision, and communication must aim to provide a positive, respectful, and solution-oriented experience.</div><div><b><br></b></div><div><b>Transparency</b></div><div>All service terms, fees, and procedures shall be communicated clearly and honestly to prevent misunderstandings and promote trust.</div><div><b><br></b></div><div><b>Accountability</b></div><div>Each representative is responsible for the accuracy, reliability, and integrity of all information and services provided to customers.</div><div><br></div><div><b>Consistency</b></div><div>Every customer shall receive the same standard of courtesy, quality, and attention, regardless of transaction size, status, or profile.</div>', '2025-10-21 11:30:34', '2025-10-21 14:11:27'),
(11, 11, '', '2025-10-21 11:40:28', '2025-10-21 11:40:28'),
